import{_ as e,o as a,c as r,ag as d}from"./chunks/framework.DmWB24NN.js";const p=JSON.parse('{"title":"CHAPTER 9: COMBAT","description":"","frontmatter":{},"headers":[],"relativePath":"Book I - Core Rules/B01 - Chapter 09_ Combat.md","filePath":"Book I - Core Rules/B01 - Chapter 09_ Combat.md"}'),n={name:"Book I - Core Rules/B01 - Chapter 09_ Combat.md"};function o(s,t,i,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="chapter-9-combat" tabindex="-1"><strong>CHAPTER 9: COMBAT</strong> <a class="header-anchor" href="#chapter-9-combat" aria-label="Permalink to &quot;**CHAPTER 9: COMBAT**&quot;">​</a></h1><h2 id="time-in-combat" tabindex="-1"><strong>Time in Combat</strong> <a class="header-anchor" href="#time-in-combat" aria-label="Permalink to &quot;**Time in Combat**&quot;">​</a></h2><p>Combat is measured in <strong>rounds</strong>. One round represents approximately one minute of exchange — not a single swing, but a sustained exchange of movement, threat, feint, and opportunity. Ten rounds equal one <strong>turn</strong>.</p><p>Most characters can perform one significant action per round. The rest of their time is movement, positioning, and the continuous defensive effort that combat requires. Significant actions include attacking, casting a spell, activating an item, moving their full movement value, stabilizing a fallen character, searching a body, retrieving a dropped item, forcing a door, and drinking a potion.</p><p>Minor actions require negligible time: speaking 20 words or fewer, drawing a weapon, dropping a held item, removing a backpack or belt, falling prone, or standing up. The GM has final judgment on what counts as minor or significant.</p><hr><h2 id="the-combat-sequence" tabindex="-1"><strong>The Combat Sequence</strong> <a class="header-anchor" href="#the-combat-sequence" aria-label="Permalink to &quot;**The Combat Sequence**&quot;">​</a></h2><p>Every round follows the same four steps.</p><p><strong>Step 1.</strong> The GM determines NPC and monster actions in secret. Spells to be cast are chosen before the players announce anything.</p><p><strong>Step 2.</strong> Players describe their characters&#39; intended actions. Declarations can be general — &quot;I move and attack the nearest enemy&quot; is sufficient. Spells begin casting at this stage and cannot be changed once declared.</p><p><strong>Step 3.</strong> Initiative is rolled. Each side rolls for the round.</p><p><strong>Step 4.</strong> Actions are resolved in initiative order, highest first.</p><p>Some abilities, spells, or situations override this sequence. The GM adjudicates as they arise.</p><hr><h2 id="initiative" tabindex="-1"><strong>Initiative</strong> <a class="header-anchor" href="#initiative" aria-label="Permalink to &quot;**Initiative**&quot;">​</a></h2><p>Initiative is rolled at the start of every round. The result determines who acts first.</p><p><strong>Formula: 1d10 + 10 − Weapon Speed</strong></p><p>Higher results act first. Weapon speed values are listed in Chapter 8. A character using a weapon with speed 4 who rolls 7 has initiative 13. A character using a weapon with speed 9 who rolls 9 has initiative 10. The first character acts before the second.</p><p>The +10 offset ensures no result falls below 1, even with the slowest weapons on the lowest rolls. The possible range is 1 through 19.</p><p>Spell casting subtracts from the caster&#39;s initiative rather than adding to it. A spell with casting time 3 reduces the caster&#39;s initiative by 3. Spells are resolved when the caster&#39;s modified initiative is reached. Longer spells — those with casting times of one round or more — resolve at the end of the round or at a future round as specified.</p><h3 id="table-9-1-initiative-modifiers" tabindex="-1"><strong>Table 9.1: Initiative Modifiers</strong> <a class="header-anchor" href="#table-9-1-initiative-modifiers" aria-label="Permalink to &quot;**Table 9.1: Initiative Modifiers**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Situation</th><th>Modifier</th></tr></thead><tbody><tr><td>Hasted</td><td>+2</td></tr><tr><td>Slowed</td><td>−2</td></tr><tr><td>High ground</td><td>+1</td></tr><tr><td>Receive charge</td><td>+2</td></tr><tr><td>Knee-deep water</td><td>−2</td></tr><tr><td>Slippery footing</td><td>−2</td></tr><tr><td>Waist-deep water</td><td>−4</td></tr><tr><td>Underwater</td><td>−6</td></tr><tr><td>Hindered (climbing, tangled, held)</td><td>−3</td></tr><tr><td>Called shot</td><td>−1</td></tr></tbody></table><h3 id="ties" tabindex="-1"><strong>Ties</strong> <a class="header-anchor" href="#ties" aria-label="Permalink to &quot;**Ties**&quot;">​</a></h3><p>When two characters share an identical initiative result — including identical weapon speeds — their actions resolve simultaneously. Both attacks are made. Both damage rolls apply. A tie can kill both combatants in the same exchange. No mechanical tiebreaker applies.</p><h3 id="the-wait-action" tabindex="-1"><strong>The Wait Action</strong> <a class="header-anchor" href="#the-wait-action" aria-label="Permalink to &quot;**The Wait Action**&quot;">​</a></h3><p>A character may declare Wait instead of acting on their initiative. Their action is held and can be triggered at any point later in the round — before, during, or immediately after another character&#39;s action.</p><p>At the start of the following round, a character who waited gains +1 to either their attack roll or their AC for that round. The player declares which benefit when the Wait is used.</p><hr><h2 id="the-attack-roll" tabindex="-1"><strong>The Attack Roll</strong> <a class="header-anchor" href="#the-attack-roll" aria-label="Permalink to &quot;**The Attack Roll**&quot;">​</a></h2><p>To attack, roll 1d20, add your Attack Bonus and all applicable modifiers, and compare the result to the target&#39;s Armor Class.</p><p><strong>d20 + Attack Bonus + Modifiers ≥ Target&#39;s AC = Hit</strong></p><p>If the result equals or exceeds the target&#39;s AC, the attack hits, and damage is rolled. If it falls short, the attack misses.</p><p>A natural 20 on the d20 is an automatic hit regardless of AC. A natural 1 is an automatic miss, and usually something inconvenient happens — the GM describes the result.</p><p>Attack Bonus is derived from class and level, as shown in the class advancement tables in Chapter 3.</p><h3 id="table-9-2-attack-roll-modifiers" tabindex="-1"><strong>Table 9.2: Attack Roll Modifiers</strong> <a class="header-anchor" href="#table-9-2-attack-roll-modifiers" aria-label="Permalink to &quot;**Table 9.2: Attack Roll Modifiers**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Situation</th><th>Modifier</th></tr></thead><tbody><tr><td>Attacker on higher ground</td><td>+1</td></tr><tr><td>Attacker invisible to the defender</td><td>+4</td></tr><tr><td>Opponent off-balance</td><td>+2</td></tr><tr><td>Opponent stunned or prone</td><td>+4</td></tr><tr><td>Opponent helpless (held, sleeping, paralyzed)</td><td>Automatic*</td></tr><tr><td>Defender surprised</td><td>+1</td></tr><tr><td>Rear attack</td><td>+2</td></tr><tr><td>Missile attack, medium range</td><td>−2</td></tr><tr><td>Missile attack, long range</td><td>−5</td></tr></tbody></table><p>* <em>In combat, a helpless opponent is hit automatically. Outside combat, they can be slain without a roll.</em></p><p><strong>Strength</strong> applies its modifier to attacks with melee weapons and bows (not crossbows). <strong>Dexterity</strong> applies its modifier to attacks with bows and hurled weapons. There is no cap on attack roll modifiers.</p><hr><h2 id="multiple-attacks" tabindex="-1"><strong>Multiple Attacks</strong> <a class="header-anchor" href="#multiple-attacks" aria-label="Permalink to &quot;**Multiple Attacks**&quot;">​</a></h2><p>When a creature attacks with multiple weapons simultaneously — natural attacks, or a warrior using two weapons — all attacks are rolled at the same time.</p><p>Multiple attacks with a single weapon are staggered. The first attack resolves on the character&#39;s initiative. Each subsequent attack resolves after every other combatant has acted in that round, in descending initiative order.</p><p>When two or more creatures have multiple attacks, their iterative attacks are ordered by initiative among themselves.</p><p><strong>Fractional attack rates.</strong> Rates like 3/2 and 5/2 alternate across rounds. 3/2 means one attack in the first round and two in the second, repeating. 5/2 is two in the first round and three in the second.</p><hr><h2 id="facing-and-space" tabindex="-1"><strong>Facing and Space</strong> <a class="header-anchor" href="#facing-and-space" aria-label="Permalink to &quot;**Facing and Space**&quot;">​</a></h2><p>Every combatant has a front, flank, and rear. Up to six attackers of equal size to the defender can engage simultaneously. Each size category larger than the defender takes up one additional space; each size category smaller takes up half a space.</p><p>Combatants face their attackers automatically until overwhelmed. Additional attackers fill the front first, then flanks, then rear. A completely surrounded defender cannot be attacked by additional assailants — the positions are full.</p><p><strong>Rear attacks</strong> deny the defender their Dexterity AC bonus. The attacker gains +2 to the attack roll.</p><hr><h2 id="weapon-length-and-space" tabindex="-1"><strong>Weapon Length and Space</strong> <a class="header-anchor" href="#weapon-length-and-space" aria-label="Permalink to &quot;**Weapon Length and Space**&quot;">​</a></h2><p>A combatant requires adequate space to swing their weapon. Medium slashing or bludgeoning weapons require roughly <strong>0.5 square meters</strong> of clear arc space. Large slashing or bludgeoning weapons require <strong>1 square meter</strong>. Piercing weapons have no arc and allow multiple combatants to fight side by side in confined spaces.</p><hr><h2 id="called-shot" tabindex="-1"><strong>Called Shot</strong> <a class="header-anchor" href="#called-shot" aria-label="Permalink to &quot;**Called Shot**&quot;">​</a></h2><p>A called shot targets a specific point: the potion on an opponent&#39;s belt, the lock on a door, a vulnerable joint in armor. The attack must be declared before initiative is rolled.</p><p>Called shots impose −1 to the caller&#39;s initiative and −4 to the attack roll. If the attack succeeds, damage is rolled normally. Called shots cannot be used to blind, maim, or cripple opponents — they affect objects and specific locations, not anatomy.</p><hr><h2 id="spell-casting-in-combat" tabindex="-1"><strong>Spell Casting in Combat</strong> <a class="header-anchor" href="#spell-casting-in-combat" aria-label="Permalink to &quot;**Spell Casting in Combat**&quot;">​</a></h2><p>Casting a spell subtracts from the caster&#39;s initiative by the spell&#39;s casting time. A caster cannot move while casting. They lose their Dexterity bonus to AC during casting.</p><p>If the caster takes damage or fails a saving throw while casting, concentration is broken — the spell fails, and that use is wiped from memory for the day.</p><hr><h2 id="two-weapon-fighting" tabindex="-1"><strong>Two-Weapon Fighting</strong> <a class="header-anchor" href="#two-weapon-fighting" aria-label="Permalink to &quot;**Two-Weapon Fighting**&quot;">​</a></h2><p>Warriors and Rogues may fight with a weapon in each hand. The primary weapon can be any one-handed weapon. The secondary weapon must be smaller and lighter than the primary, with the exception that any combination of dagger, knife, and dirk may be paired freely. No shield larger than a buckler may be carried alongside two weapons.</p><p>Two-weapon fighting grants one additional attack per round. The progression: a standard 1/round becomes 2/round; 3/2 becomes 5/2; 5/2 becomes 7/2.</p><p><strong>Penalties:</strong> −2 to the primary hand, −4 to the non-dominant hand. A positive Dexterity missile attack modifier reduces these penalties (to a maximum reduction of +0 before other modifiers). A negative Dexterity modifier increases them.</p><p>See Chapter 6 for the Dual-Weapon Method, which further reduces these penalties through training.</p><h3 id="non-dominant-hand" tabindex="-1"><strong>Non-Dominant Hand</strong> <a class="header-anchor" href="#non-dominant-hand" aria-label="Permalink to &quot;**Non-Dominant Hand**&quot;">​</a></h3><p>A character using only their non-dominant hand — through injury, circumstance, or choice — suffers a −2 penalty to all actions with that hand, modified by their Dexterity missile attack bonus to a maximum reduction of +0.</p><hr><h2 id="movement-in-combat" tabindex="-1"><strong>Movement in Combat</strong> <a class="header-anchor" href="#movement-in-combat" aria-label="Permalink to &quot;**Movement in Combat**&quot;">​</a></h2><p>All combatants may move <strong>three times their movement value in meters</strong> per round.</p><h3 id="movement-and-melee" tabindex="-1"><strong>Movement and Melee</strong> <a class="header-anchor" href="#movement-and-melee" aria-label="Permalink to &quot;**Movement and Melee**&quot;">​</a></h3><p>A combatant can move up to <strong>half their full movement distance</strong> and still make a melee attack in the same round. Movement ends if the defender actively blocks the path or the half-movement limit is reached.</p><h3 id="movement-and-ranged-attacks" tabindex="-1"><strong>Movement and Ranged Attacks</strong> <a class="header-anchor" href="#movement-and-ranged-attacks" aria-label="Permalink to &quot;**Movement and Ranged Attacks**&quot;">​</a></h3><p>Moving and firing simultaneously reduces the rate of fire. A combatant moving up to half their movement rate fires at half their normal ROF, rounded down. Weapons with ROF 1 or lower gain one additional round between shots.</p><p><em>Example: A short bow&#39;s normal ROF of 2/round becomes 1/round while moving. A light crossbow&#39;s normal ROF of 1/round becomes 1/2 rounds.</em></p><h3 id="charge" tabindex="-1"><strong>Charge</strong> <a class="header-anchor" href="#charge" aria-label="Permalink to &quot;**Charge**&quot;">​</a></h3><p>A charging character increases their movement by 50% and gains +2 to their first melee attack. The target gains +2 to their own initiative (possibly allowing them to act first), the charger loses their Dexterity bonus to AC for the round, and the charger&#39;s AC is reduced by 1 for the round of the charge.</p><h3 id="retreat" tabindex="-1"><strong>Retreat</strong> <a class="header-anchor" href="#retreat" aria-label="Permalink to &quot;**Retreat**&quot;">​</a></h3><p><strong>Withdraw.</strong> A careful withdrawal from melee allows the character to move their full movement value while keeping their defenses. Opponents cannot exploit the withdrawal.</p><p><strong>Flee.</strong> A fleeing character drops all defenses and moves at <strong>triple their normal combat speed</strong>. Every adjacent opponent may immediately make all of their attacks for the round against the fleeing character as free attacks — these do not count against their normal attack limit.</p><hr><h2 id="non-lethal-combat" tabindex="-1"><strong>Non-Lethal Combat</strong> <a class="header-anchor" href="#non-lethal-combat" aria-label="Permalink to &quot;**Non-Lethal Combat**&quot;">​</a></h2><p>Three forms of unarmed engagement exist: brawling, wrestling, and overbearing.</p><h3 id="brawling" tabindex="-1"><strong>Brawling</strong> <a class="header-anchor" href="#brawling" aria-label="Permalink to &quot;**Brawling**&quot;">​</a></h3><p>Attacking with bare hands, feet, or other primary appendages. An attack roll is made against the target&#39;s normal AC. Strength applies to damage.</p><p>Damage from brawling: 25% is lethal, 75% is non-lethal. Non-lethal damage is tracked separately. Any healing effect removes equal amounts of both. A character reduced to 0 HP while carrying non-lethal damage falls unconscious immediately. An attacker may pull their blows to deal no lethal damage, but the KO chance still applies.</p><h3 id="table-9-3-brawling-and-wrestling-results" tabindex="-1"><strong>Table 9.3: Brawling and Wrestling Results</strong> <a class="header-anchor" href="#table-9-3-brawling-and-wrestling-results" aria-label="Permalink to &quot;**Table 9.3: Brawling and Wrestling Results**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Roll</th><th>Brawl</th><th>Dmg</th><th>%KO</th><th>Wrestle</th></tr></thead><tbody><tr><td>20+</td><td>Haymaker</td><td>2</td><td>10%</td><td>Bear hug*</td></tr><tr><td>19</td><td>Back kick</td><td>0</td><td>1%</td><td>Arm twist</td></tr><tr><td>18</td><td>Rabbit punch</td><td>1</td><td>3%</td><td>Kick</td></tr><tr><td>17</td><td>Kidney punch</td><td>1</td><td>5%</td><td>Trip</td></tr><tr><td>16</td><td>Front kick</td><td>1</td><td>2%</td><td>Elbow smash</td></tr><tr><td>15</td><td>Jab</td><td>2</td><td>6%</td><td>Arm lock*</td></tr><tr><td>14</td><td>Uppercut</td><td>1</td><td>8%</td><td>Leg twist</td></tr><tr><td>13</td><td>Crescent kick</td><td>2</td><td>10%</td><td>Leg lock</td></tr><tr><td>12</td><td>Roundhouse</td><td>1</td><td>5%</td><td>Throw</td></tr><tr><td>11</td><td>Hook</td><td>2</td><td>10%</td><td>Gouge</td></tr><tr><td>10</td><td>Back fist</td><td>1</td><td>3%</td><td>Elbow smash</td></tr><tr><td>9</td><td>Combination</td><td>1</td><td>10%</td><td>Leg lock*</td></tr><tr><td>8</td><td>Reverse kick</td><td>1</td><td>9%</td><td>Headlock*</td></tr><tr><td>7</td><td>Combination</td><td>2</td><td>10%</td><td>Throw</td></tr><tr><td>6</td><td>Side kick</td><td>2</td><td>8%</td><td>Gouge</td></tr><tr><td>5</td><td>Overhand</td><td>1</td><td>3%</td><td>Kick</td></tr><tr><td>4</td><td>Cross</td><td>2</td><td>5%</td><td>Arm lock*</td></tr><tr><td>3</td><td>Hook</td><td>2</td><td>12%</td><td>Gouge</td></tr><tr><td>2</td><td>Uppercut</td><td>2</td><td>15%</td><td>Headlock*</td></tr><tr><td>1</td><td>Glancing blow</td><td>0</td><td>2%</td><td>Leg twist</td></tr><tr><td>&lt;1</td><td>Wild swing</td><td>2</td><td>25%</td><td>Bear hug*</td></tr></tbody></table><p>* <em>Holds persist until broken. A hold is broken by a throw, gouge, assistance from another character, or a melee weapon attack. Holds deal 1 automatic point of damage per round maintained.</em></p><p><strong>%KO.</strong> Each successful brawling attack has this chance to stun the victim for 1d10 rounds.</p><p><strong>Brawling damage with gauntlets</strong> increases to 1d3.</p><h3 id="wrestling" tabindex="-1"><strong>Wrestling</strong> <a class="header-anchor" href="#wrestling" aria-label="Permalink to &quot;**Wrestling**&quot;">​</a></h3><p>Both hands must be free. An attack roll is made against the target&#39;s normal AC. Armor heavier than leather penalizes the roll.</p><h3 id="table-9-4-armor-modifiers-for-wrestling" tabindex="-1"><strong>Table 9.4: Armor Modifiers for Wrestling</strong> <a class="header-anchor" href="#table-9-4-armor-modifiers-for-wrestling" aria-label="Permalink to &quot;**Table 9.4: Armor Modifiers for Wrestling**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Armor</th><th>Attack Modifier</th></tr></thead><tbody><tr><td>Studded leather</td><td>−1</td></tr><tr><td>Chain, ring, or scale mail</td><td>−2</td></tr><tr><td>Banded, splint, or plate variants</td><td>−4</td></tr><tr><td>Field plate</td><td>−7</td></tr><tr><td>Full plate</td><td>−9</td></tr></tbody></table><h3 id="overbearing" tabindex="-1"><strong>Overbearing</strong> <a class="header-anchor" href="#overbearing" aria-label="Permalink to &quot;**Overbearing**&quot;">​</a></h3><p>An attempt to drag an opponent down and pin them. Make an attack roll against the target. Each size category the attacker is larger than the defender adds +4 to the roll; each size category smaller subtracts 4. The attacker suffers −2 for each additional leg beyond two the defender has. Amorphous creatures have no legs and impose no penalty.</p><p>On a successful hit, the opponent is pulled down. A second successful overbearing attack pins them. For each attacker beyond the first, add +1 to the roll — with the weakest attacker making the roll and the largest attacker&#39;s size providing the modifier.</p><h3 id="weapons-against-unarmed-combatants" tabindex="-1"><strong>Weapons Against Unarmed Combatants</strong> <a class="header-anchor" href="#weapons-against-unarmed-combatants" aria-label="Permalink to &quot;**Weapons Against Unarmed Combatants**&quot;">​</a></h3><p>An armed character being brawled, wrestled, or overbeared immediately gains one free attack with +4 to the roll before the unarmed attack resolves. Wrestling allows both combatants to attack each other with small weapons.</p><h3 id="non-lethal-weapon-attacks" tabindex="-1"><strong>Non-Lethal Weapon Attacks</strong> <a class="header-anchor" href="#non-lethal-weapon-attacks" aria-label="Permalink to &quot;**Non-Lethal Weapon Attacks**&quot;">​</a></h3><p>Slashing and piercing weapons can deal non-lethal damage intentionally. Ranged attacks cannot be made non-lethal. Attacking non-lethally applies −4 to the attack roll. 50% of damage dealt is non-lethal.</p><hr><h2 id="ranged-attacks" tabindex="-1"><strong>Ranged Attacks</strong> <a class="header-anchor" href="#ranged-attacks" aria-label="Permalink to &quot;**Ranged Attacks**&quot;">​</a></h2><p>Ranged attacks use the same roll formula as melee: d20 + Attack Bonus + Modifiers ≥ target&#39;s AC.</p><p>Strength modifiers apply to damage rolls for hurled weapons and, in some cases, to both attack and damage for bows. Dexterity modifiers apply to attack rolls for all aimed ranged weapons.</p><p>Rate of fire is handled as a multiple attack (see above).</p><p>Ranged weapons fire in a straight line by default. Arcing fire is possible — calculate additional range for the arc. Some weapons, like the staff sling, require arced fire and have a minimum range.</p><hr><h2 id="cover-and-concealment" tabindex="-1"><strong>Cover and Concealment</strong> <a class="header-anchor" href="#cover-and-concealment" aria-label="Permalink to &quot;**Cover and Concealment**&quot;">​</a></h2><p><strong>Concealment</strong> hides a character but provides no physical barrier (a bush, a tapestry). <strong>Cover</strong> hides and physically protects (a wall, furniture). Both apply penalties to ranged attacks against the protected defender.</p><h3 id="table-9-5-cover-and-concealment-modifiers" tabindex="-1"><strong>Table 9.5: Cover and Concealment Modifiers</strong> <a class="header-anchor" href="#table-9-5-cover-and-concealment-modifiers" aria-label="Permalink to &quot;**Table 9.5: Cover and Concealment Modifiers**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Degree of Protection</th><th>Cover (Attack Modifier)</th><th>Concealment (Attack Modifier)</th></tr></thead><tbody><tr><td>25% hidden</td><td>−1</td><td>−1</td></tr><tr><td>50% hidden</td><td>−2</td><td>−2</td></tr><tr><td>75% hidden</td><td>−4</td><td>−3</td></tr><tr><td>90%+ hidden</td><td>−7</td><td>−4</td></tr></tbody></table><p>Cover (but not concealment) also grants the defender a bonus to Reflex saves against area effects like fireballs. At 90%+ cover, the defender suffers half damage on a failed save and no damage on a successful save — provided the cover actually blocks the effect. A fireball that detonates behind the cover applies normally.</p><hr><h2 id="firing-into-crowds" tabindex="-1"><strong>Firing into Crowds</strong> <a class="header-anchor" href="#firing-into-crowds" aria-label="Permalink to &quot;**Firing into Crowds**&quot;">​</a></h2><p>Targeting a specific creature in a melee requires care. Choose the target and roll the attack with all normal modifiers.</p><p>If the modified roll is too low to hit the target&#39;s AC or the AC of any adjacent creature, it misses entirely. If the modified roll could hit the target or any adjacent creature, the GM randomly determines the actual target. Assign each creature a number based on size: Small or smaller = 1, Medium = 2, Large = 3, Huge = 8, Gargantuan = 12, Colossal = 16. Divide each creature&#39;s number by the total to find their hit probability. Compare the randomly determined target&#39;s AC against the original roll to resolve the hit.</p><p>A called shot at −6 guarantees only the intended target is struck, though miss-hit remains possible against adjacent allies at additional concealment penalties.</p><hr><h2 id="indirect-missiles" tabindex="-1"><strong>Indirect Missiles</strong> <a class="header-anchor" href="#indirect-missiles" aria-label="Permalink to &quot;**Indirect Missiles**&quot;">​</a></h2><p>An indirect missile targets a point, not a creature. Flasks of Greek fire, acid vials, and holy water are typical examples.</p><p>Attack roll: d20 against AC 10 to target a specific point. Penalties apply for concealment, cover, or limited visibility.</p><p>On a miss, the missile scatters. Roll 1d10 and consult the scatter diagram (direction). Distance of scatter by range: short range <strong>1d2 m</strong>, medium range <strong>1d3 m</strong>, long range <strong>1d6 m</strong>.</p><p>All creatures in the effective area take a direct hit. Creatures within <strong>1 m</strong> of the effective area take splash damage.</p><h3 id="table-9-6-indirect-missile-effects" tabindex="-1"><strong>Table 9.6: Indirect Missile Effects</strong> <a class="header-anchor" href="#table-9-6-indirect-missile-effects" aria-label="Permalink to &quot;**Table 9.6: Indirect Missile Effects**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Effective Area</th><th>Direct Hit</th><th>Splash</th></tr></thead><tbody><tr><td>Acid</td><td>0.3 m diameter</td><td>2d4 HP</td><td>1 HP</td></tr><tr><td>Holy water</td><td>0.3 m diameter</td><td>2d3 HP</td><td>2 HP</td></tr><tr><td>Greek fire</td><td>1 m diameter</td><td>2d6 HP / 1d6 HP per round</td><td>1d3 HP</td></tr><tr><td>Poison</td><td>0.3 m diameter</td><td>Special</td><td>Special</td></tr></tbody></table><p><strong>Acid</strong> damage cannot be regenerated. <strong>Holy water</strong> and <strong>unholy water</strong> deal acid-type damage (non-regenerating) to undead, evil outsiders, paladins, and good outsiders respectively. No effect on gaseous creatures. <strong>Oil</strong> requires a lit source to ignite — one action to splash, a second to ignite. <strong>Poison</strong> in indirect missile form affects only direct-hit targets unless gaseous.</p><p><strong>Heavy objects.</strong> Boulders and iron balls do not shatter. They roll <strong>1d8 m</strong> after impact, striking everything in their path. Scatter distance is doubled on a miss. Creatures in the path after the first bounce are attacked at −2 per <strong>3 m</strong> of travel.</p><hr><h2 id="saving-throws" tabindex="-1"><strong>Saving Throws</strong> <a class="header-anchor" href="#saving-throws" aria-label="Permalink to &quot;**Saving Throws**&quot;">​</a></h2><p>Saving throws represent a character&#39;s chance to avoid or reduce a harmful effect. Three saves exist, each tied to an ability score established at character creation and advancing independently thereafter.</p><table tabindex="0"><thead><tr><th>Save</th><th>Governing Attribute</th><th>Resists</th></tr></thead><tbody><tr><td>Fortitude</td><td>Constitution</td><td>Poison, disease, death magic, energy drain, petrification, polymorph, physical trauma</td></tr><tr><td>Reflex</td><td>Dexterity</td><td>Area effects, breath weapons, traps, wands and rods, anything requiring physical evasion</td></tr><tr><td>Will</td><td>Wisdom</td><td>Charm, illusions, fear, mental influence, most spells targeting the mind directly</td></tr></tbody></table><p><strong>Rolling a save:</strong> 1d20 + modifiers, equal to or less than the save score</p><p><strong>Score independence.</strong> Save scores advance separately from ability scores once established at character creation. An effect that drains Constitution does not reduce the character&#39;s Fortitude save — and an effect that boosts a save score does not raise the corresponding attribute. These are separate character resources.</p><p><strong>Converting old categories.</strong> For reference, when consulting older material:</p><table tabindex="0"><thead><tr><th>Old Category</th><th>New Save</th></tr></thead><tbody><tr><td>Paralysis / Poison / Death Magic</td><td>Fortitude</td></tr><tr><td>Rod / Staff / Wand</td><td>Reflex</td></tr><tr><td>Petrification / Polymorph</td><td>Fortitude</td></tr><tr><td>Breath Weapon</td><td>Reflex</td></tr><tr><td>Spell (default)</td><td>Will</td></tr><tr><td>Spell (evasion-based)</td><td>Reflex</td></tr></tbody></table><h3 id="save-progression" tabindex="-1"><strong>Save Progression</strong> <a class="header-anchor" href="#save-progression" aria-label="Permalink to &quot;**Save Progression**&quot;">​</a></h3><p>Each save is either <strong>strong</strong> or <strong>weak</strong> for a given class, as listed in Chapter 3.</p><table tabindex="0"><thead><tr><th>Save Type</th><th>Progression</th></tr></thead><tbody><tr><td>Strong</td><td>+1 every 4 levels</td></tr><tr><td>Weak</td><td>+1 every 8 levels</td></tr></tbody></table><p>Multiclass characters use the best applicable save score across their classes for each of the three saves independently.</p><h3 id="modifiers-to-saves" tabindex="-1"><strong>Modifiers to Saves</strong> <a class="header-anchor" href="#modifiers-to-saves" aria-label="Permalink to &quot;**Modifiers to Saves**&quot;">​</a></h3><p><strong>Magical armor.</strong> Enchantment bonuses on magical armor add to saves against physical damage effects — fire, disintegration, impact damage. They do not protect against gas, poison, mental effects, or anything that does not inflict external physical damage.</p><p><strong>Ability scores.</strong> The Wisdom Mental Defense Modifier (Table 1.5) adds to Will saves. High Constitution&#39;s Poison Resistance (Table 1.2) adds to Fortitude saves against poison. The Dexterity Surprise Modifier (Table 1.3) adds to Reflex saves against evasion-based effects.</p><p><strong>Specific spells or items.</strong> Potent effects carry penalties to the relevant save. Weak effects carry bonuses. Specific magical items that grant save bonuses apply to the applicable new save category.</p><p><strong>Situation modifiers.</strong> The GM may apply bonuses or penalties from −4 to +4 based on circumstances.</p><h3 id="voluntarily-failing" tabindex="-1"><strong>Voluntarily Failing</strong> <a class="header-anchor" href="#voluntarily-failing" aria-label="Permalink to &quot;**Voluntarily Failing**&quot;">​</a></h3><p>A character may consciously choose to fail a saving throw. The decision must be stated explicitly before the roll. The effect applies normally.</p><h3 id="ability-checks-as-saves" tabindex="-1"><strong>Ability Checks as Saves</strong> <a class="header-anchor" href="#ability-checks-as-saves" aria-label="Permalink to &quot;**Ability Checks as Saves**&quot;">​</a></h3><p>When a character might avoid damage through a physical action — catching a ledge on a fall, landing properly after a drop — the GM may call for an ability check in place of a save. A Strength check to jam a pick into a cliff face; a Dexterity check to land properly; a Constitution check to resist environmental exhaustion. These use the standard NWP roll mechanic (Chapter 7).</p><hr><h2 id="magic-resistance" tabindex="-1"><strong>Magic Resistance</strong> <a class="header-anchor" href="#magic-resistance" aria-label="Permalink to &quot;**Magic Resistance**&quot;">​</a></h2><p>Magic resistance is an innate property of certain creatures. It requires no conscious effort and is always active unless the creature deliberately lowers it.</p><p>Magic resistance is expressed as a percentile. When a spell targets a magic-resistant creature, roll percentile dice. If the result equals or falls below the resistance value, the spell is fully resisted. If the roll exceeds the resistance, the spell affects the creature normally — saves still apply as usual.</p><p>Magic resistance applies to direct spells and spell-like powers, including beneficial effects. It does not apply to magic weapons, nor to secondary effects of spells (objects knocked over by an earthquake, for instance).</p><p><strong>Targeted spells.</strong> If a single target resists, or if every target in a group resists, the spell fails entirely.</p><p><strong>Area effect spells.</strong> The spell goes off normally. Only creatures that succeed on their magic resistance check are unaffected.</p><p><strong>Continuous spells.</strong> Resistance activates when the creature enters or is targeted by the effect. A successful resistance check does not dispel the continuous spell — it only protects the individual creature.</p><p><strong>Permanent spells.</strong> A magic-resistant creature remains unaffected while within the spell&#39;s area. The spell itself is not negated.</p><hr><h2 id="weapon-immunity" tabindex="-1"><strong>Weapon Immunity</strong> <a class="header-anchor" href="#weapon-immunity" aria-label="Permalink to &quot;**Weapon Immunity**&quot;">​</a></h2><p>Some creatures are immune to damage from normal weapons. A visibly wounded immune creature suffers no actual hit point loss from a non-qualifying weapon. Magical effects delivered by the weapon — fire, poison, and similar — still apply normally.</p><p>The two most common immunities are bypassed by magic weapons of sufficient enchantment bonus, or by weapons forged entirely from silver.</p><h3 id="table-9-7-creature-hd-and-weapon-immunity" tabindex="-1"><strong>Table 9.7: Creature HD and Weapon Immunity</strong> <a class="header-anchor" href="#table-9-7-creature-hd-and-weapon-immunity" aria-label="Permalink to &quot;**Table 9.7: Creature HD and Weapon Immunity**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Creature HD</th><th>Overcomes</th></tr></thead><tbody><tr><td>4 HD</td><td>+1 weapon immunity</td></tr><tr><td>6 HD</td><td>+2 weapon immunity</td></tr><tr><td>8 HD</td><td>+3 weapon immunity</td></tr><tr><td>10 HD</td><td>+4 weapon immunity</td></tr></tbody></table><p>Natural attacks of creatures can function as magic weapons for this purpose, based on HD. This applies only to creatures — player characters and NPCs cannot claim this benefit.</p><h2 id="damage-vulnerability-and-resistance" tabindex="-1"><strong>Damage Vulnerability and Resistance</strong> <a class="header-anchor" href="#damage-vulnerability-and-resistance" aria-label="Permalink to &quot;**Damage Vulnerability and Resistance**&quot;">​</a></h2><p>Some armor types perform poorly against certain kinds of force, and better against others. These interactions are noted as tags in the armor entries in Chapter 8, and on specific creatures in their stat blocks.</p><ul><li><strong>Vulnerable:</strong> The armor or creature takes higher weapon damage dice. Roll the weapon&#39;s damage dice twice and use the higher result.</li><li><strong>Resistant:</strong> The armor or creature takes reduced weapon damage. Roll the weapon&#39;s damage dice twice and use the lower result.</li></ul><p>Neither tag affects flat modifiers — Strength bonuses, enchantment bonuses, and similar additions are applied once, after the dice are resolved.</p><p>Vulnerability and resistance apply only to the damage type that triggered them. A character wearing plate mail is vulnerable to bludgeoning — a mace rolls twice and takes the higher result. A sword against the same target rolls normally.</p><p>When a damage source qualifies for both a vulnerability and a resistance simultaneously — from stacked effects or unusual circumstances — they cancel out, and damage is rolled once, normally.</p><hr><h2 id="special-attacks" tabindex="-1"><strong>Special Attacks</strong> <a class="header-anchor" href="#special-attacks" aria-label="Permalink to &quot;**Special Attacks**&quot;">​</a></h2><h3 id="turn-undead" tabindex="-1"><strong>Turn Undead</strong> <a class="header-anchor" href="#turn-undead" aria-label="Permalink to &quot;**Turn Undead**&quot;">​</a></h3><p>Clerics and Paladins can turn or destroy undead by channeling divine power through a holy object. Druids cannot turn undead.</p><p><strong>Procedure.</strong> Turning requires a holy object (see Chapter 8), both hands free except for the one presenting the symbol, and clear speech. All undead able to see the priest are subject to the attempt. Turning counts as a hostile action and occurs on the priest&#39;s initiative. It can be used once per encounter. Multiple priests may each attempt to turn simultaneously.</p><p>A Paladin is treated as a Cleric two levels lower for turning purposes.</p><p>Cross-reference the undead creature&#39;s HD (down the left column) against the priest&#39;s level (across the top). If a number is listed, roll 1d20. Meeting or exceeding the target succeeds.</p><ul><li><strong>T</strong> — the undead is turned and flees.</li><li><strong>D</strong> — the undead is destroyed instantly.</li><li><strong>—</strong> — the priest cannot affect this undead at their current level.</li><li><strong>D*</strong> — 2d4 additional creatures of this type are also destroyed.</li></ul><p>A successful turn affects 2d6 undead. Mixed groups are affected starting with the lowest HD. Turned undead retreat until out of the priest&#39;s sight and remain hidden until they believe the priest has passed; intelligent undead may attempt to attack again once the priest is gone. If the priest forces the undead closer than <strong>3 m</strong>, the turning breaks immediately.</p><p>Turning lasts as long as the priest maintains concentration — active engagement in other combat is possible but the priest must remain aware of the turned undead and keep hold of their holy symbol.</p><h3 id="table-9-8-turn-undead" tabindex="-1"><strong>Table 9.8: Turn Undead</strong> <a class="header-anchor" href="#table-9-8-turn-undead" aria-label="Permalink to &quot;**Table 9.8: Turn Undead**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Undead HD</th><th>Cl 1</th><th>Cl 2</th><th>Cl 3</th><th>Cl 4</th><th>Cl 5</th><th>Cl 6</th><th>Cl 7</th><th>Cl 8</th><th>Cl 9</th><th>Cl 10</th><th>Cl 11</th><th>Cl 12</th><th>Cl 13</th><th>Cl 14+</th></tr></thead><tbody><tr><td>Under 1 HD</td><td>10</td><td>7</td><td>4</td><td>T</td><td>T</td><td>D</td><td>D</td><td>D*</td><td>D*</td><td>D*</td><td>D*</td><td>D*</td><td>D*</td><td>D*</td></tr><tr><td>1 HD</td><td>13</td><td>10</td><td>7</td><td>4</td><td>T</td><td>T</td><td>D</td><td>D</td><td>D*</td><td>D*</td><td>D*</td><td>D*</td><td>D*</td><td>D*</td></tr><tr><td>2 HD</td><td>16</td><td>13</td><td>10</td><td>7</td><td>4</td><td>T</td><td>T</td><td>D</td><td>D</td><td>D*</td><td>D*</td><td>D*</td><td>D*</td><td>D*</td></tr><tr><td>3 HD</td><td>19</td><td>16</td><td>13</td><td>10</td><td>7</td><td>4</td><td>T</td><td>T</td><td>D</td><td>D</td><td>D*</td><td>D*</td><td>D*</td><td>D*</td></tr><tr><td>4 HD</td><td>20</td><td>19</td><td>16</td><td>13</td><td>10</td><td>7</td><td>4</td><td>T</td><td>T</td><td>D</td><td>D</td><td>D*</td><td>D*</td><td>D*</td></tr><tr><td>5 HD</td><td>—</td><td>20</td><td>19</td><td>16</td><td>13</td><td>10</td><td>7</td><td>4</td><td>T</td><td>T</td><td>D</td><td>D</td><td>D*</td><td>D*</td></tr><tr><td>6 HD</td><td>—</td><td>—</td><td>20</td><td>19</td><td>16</td><td>13</td><td>10</td><td>7</td><td>4</td><td>T</td><td>T</td><td>D</td><td>D</td><td>D*</td></tr><tr><td>7 HD</td><td>—</td><td>—</td><td>—</td><td>20</td><td>19</td><td>16</td><td>13</td><td>10</td><td>7</td><td>4</td><td>T</td><td>T</td><td>D</td><td>D</td></tr><tr><td>8 HD</td><td>—</td><td>—</td><td>—</td><td>—</td><td>20</td><td>19</td><td>16</td><td>13</td><td>10</td><td>7</td><td>4</td><td>T</td><td>T</td><td>D</td></tr><tr><td>9 HD</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>20</td><td>19</td><td>16</td><td>13</td><td>10</td><td>7</td><td>4</td><td>T</td><td>T</td></tr><tr><td>10 HD</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>20</td><td>19</td><td>16</td><td>13</td><td>10</td><td>7</td><td>4</td><td>T</td></tr><tr><td>11+ HD</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>20</td><td>19</td><td>16</td><td>13</td><td>10</td><td>7</td><td>4</td></tr><tr><td>Special**</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>20</td><td>19</td><td>16</td><td>13</td><td>10</td><td>7</td></tr></tbody></table><p>** <em>Special undead include unique monsters greater than 11 HD, undead native to the negative material plane, and undead from the outer planes regardless of HD.</em></p><h3 id="dominate-undead" tabindex="-1"><strong>Dominate Undead</strong> <a class="header-anchor" href="#dominate-undead" aria-label="Permalink to &quot;**Dominate Undead**&quot;">​</a></h3><p>Evil priests do not turn undead — they command them. A successful turning result means the undead follows the first order given until it is completed, then is no longer beholden. A D result means the undead is fully subservient. An evil priest can command up to 12 undead at one time. Evil priests may also attempt to dominate paladins, treating themselves as three levels lower than their actual level.</p><h3 id="gaze-attacks" tabindex="-1"><strong>Gaze Attacks</strong> <a class="header-anchor" href="#gaze-attacks" aria-label="Permalink to &quot;**Gaze Attacks**&quot;">​</a></h3><p>Creatures with gaze attacks affect any character looking at them. All combatants facing the creature are considered to be meeting its gaze each round.</p><p><strong>Averting eyes.</strong> A character looking only in the general direction of the creature averts their gaze. There is a 20% chance per round of accidentally meeting the gaze anyway.</p><p><strong>Closing eyes or looking at the ground.</strong> Completely safe from the gaze, but the character is treated as blind for attack purposes.</p><p><strong>Mirror or reflective surface.</strong> The character may fight while watching the creature&#39;s reflection. This requires a free hand and imposes −2 to attack rolls. The character loses their Dexterity AC bonus.</p><p>A creature with a gaze attack may choose not to look at its opponents, suppressing its own ability.</p><h3 id="breath-weapons" tabindex="-1"><strong>Breath Weapons</strong> <a class="header-anchor" href="#breath-weapons" aria-label="Permalink to &quot;**Breath Weapons**&quot;">​</a></h3><p>Breath weapons originate at the creature&#39;s mouth and spread through their effective area. No attack roll is required. All creatures caught in the area are affected. Affected characters make a <strong>Reflex save</strong> for half damage.</p><h3 id="charmed-creatures" tabindex="-1"><strong>Charmed Creatures</strong> <a class="header-anchor" href="#charmed-creatures" aria-label="Permalink to &quot;**Charmed Creatures**&quot;">​</a></h3><p>A charmed creature follows the caster&#39;s orders. Charmed monsters fight with normal weapons but will not use special abilities unless directly commanded. A charmed spellcaster will reveal their memorized spells — there is also a 25% chance they will cast a spell harmful to both themselves and their master.</p><p>Charmed creatures cannot act on their own judgment. Orders must be specific and clear. They will not follow self-destructive orders such as suicide, but combat against impossible odds is not considered self-destructive. Charmed monsters with innate mental charm powers (vampires and similar) communicate orders directly without language.</p><h3 id="innate-abilities" tabindex="-1"><strong>Innate Abilities</strong> <a class="header-anchor" href="#innate-abilities" aria-label="Permalink to &quot;**Innate Abilities**&quot;">​</a></h3><p>Some creatures have spells or powers they activate mentally as a basic action. These have no casting time and require no components. Variable spell effects use the creature&#39;s HD to determine level equivalence. If the creature falls below the minimum level for the spell&#39;s lowest effect, it functions at that lowest level.</p><hr><h2 id="morale" tabindex="-1"><strong>Morale</strong> <a class="header-anchor" href="#morale" aria-label="Permalink to &quot;**Morale**&quot;">​</a></h2><p>Morale governs the willingness of NPCs and creatures to continue fighting. Player characters do not roll morale checks — the GM handles all NPC and creature morale.</p><p>Animals rarely fight to the death except when defending lair or young. Unintelligent creatures — constructs, mindless undead, plants — fight without self-preservation unless specifically controlled. Intelligent creatures assess the situation.</p><p>The GM may adjudicate morale breaks without rolling. When a roll is warranted, use the following guidelines to determine when to check.</p><p><strong>Trigger conditions for a morale check:</strong></p><ul><li>First round after being surprised</li><li>Faced with a clearly superior force</li><li>An ally is slain by magic</li><li>25% of the group has fallen</li><li>50% of the group has fallen</li><li>Each additional companion death after 50% casualties</li><li>The group&#39;s leader deserts or falls</li><li>Ordered to attempt a suicidal task</li><li>Fighting a creature they cannot harm</li><li>Surrounded or completely overwhelmed</li><li>Offered a bribe or chance to surrender (when other morale conditions are already in effect)</li></ul><p><strong>Rolling the check.</strong> Roll 2d10 and compare to the creature&#39;s morale rating. If the result equals or falls below the morale rating, the creature fights on. If the result exceeds the rating, it retreats, surrenders, or complies.</p><h3 id="table-9-9-base-morale-ratings" tabindex="-1"><strong>Table 9.9: Base Morale Ratings</strong> <a class="header-anchor" href="#table-9-9-base-morale-ratings" aria-label="Permalink to &quot;**Table 9.9: Base Morale Ratings**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Creature Type</th><th>Morale</th></tr></thead><tbody><tr><td>Unintelligent</td><td>18</td></tr><tr><td>Animal, docile</td><td>3</td></tr><tr><td>Animal, predator</td><td>7</td></tr><tr><td>Intelligent animal</td><td>12</td></tr><tr><td>Commoner</td><td>7</td></tr><tr><td>Mob</td><td>9</td></tr><tr><td>Militia</td><td>10</td></tr><tr><td>Trained soldiers</td><td>12</td></tr><tr><td>Elite soldiers</td><td>14</td></tr><tr><td>Hirelings</td><td>12</td></tr><tr><td>Henchmen</td><td>15</td></tr></tbody></table><h3 id="table-9-10-morale-modifiers" tabindex="-1"><strong>Table 9.10: Morale Modifiers</strong> <a class="header-anchor" href="#table-9-10-morale-modifiers" aria-label="Permalink to &quot;**Table 9.10: Morale Modifiers**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Situation</th><th>Modifier</th></tr></thead><tbody><tr><td>Abandoned by allies</td><td>−2</td></tr><tr><td>Creature lost 25% HP</td><td>−1</td></tr><tr><td>Creature lost 50% HP</td><td>−2</td></tr><tr><td>Creature is Chaotic</td><td>−1</td></tr><tr><td>Creature fighting a hated enemy</td><td>+4</td></tr><tr><td>Creature is Lawful</td><td>+1</td></tr><tr><td>Creature was surprised</td><td>−1</td></tr><tr><td>Creatures fighting spellcasters</td><td>−2</td></tr><tr><td>Creatures with ½ HD or less</td><td>−2</td></tr><tr><td>Creatures with less than 1 HD</td><td>−1</td></tr><tr><td>Creatures with 4–8 HD</td><td>+1</td></tr><tr><td>Creatures with 9–14 HD</td><td>+2</td></tr><tr><td>Creatures with 15+ HD</td><td>+3</td></tr><tr><td>Defending lair</td><td>+3</td></tr><tr><td>Terrain advantage</td><td>+1</td></tr><tr><td>Each additional check this round</td><td>−1</td></tr><tr><td>Leader of different alignment</td><td>−1</td></tr><tr><td>Most powerful ally defeated</td><td>−2</td></tr><tr><td>NPC treated exceptionally well</td><td>+2</td></tr><tr><td>NPC treated poorly</td><td>−2</td></tr><tr><td>No opponents defeated</td><td>−1</td></tr><tr><td>Outnumbered 3-to-1</td><td>−2</td></tr><tr><td>Outnumber opponents 3-to-1</td><td>+2</td></tr><tr><td>Unable to affect opponents</td><td>−4</td></tr><tr><td>Spellcaster as an ally</td><td>+2</td></tr></tbody></table><hr><h2 id="damaging-objects" tabindex="-1"><strong>Damaging Objects</strong> <a class="header-anchor" href="#damaging-objects" aria-label="Permalink to &quot;**Damaging Objects**&quot;">​</a></h2><p>Most equipment does not require hit point tracking — characters maintain their gear during downtime. If someone deliberately tries to destroy an item, track HP or call for an item saving throw.</p><p>To attack an object in melee, the weapon must be capable of damaging it. Blunt weapons are poor for cutting; piercing weapons are useless against doors. Hitting a large, immobile object in melee is automatic. Targeting a specific small part (a doorknob, a strap) requires a called shot.</p><p>Ranged attacks against objects treat the object&#39;s size and hardness as AC.</p><h3 id="table-9-11-object-hit-points" tabindex="-1"><strong>Table 9.11: Object Hit Points</strong> <a class="header-anchor" href="#table-9-11-object-hit-points" aria-label="Permalink to &quot;**Table 9.11: Object Hit Points**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Object</th><th>HP</th><th>Effective Damage Type</th><th>Ranged AC</th></tr></thead><tbody><tr><td>Chair</td><td>1d8+1</td><td>Bludgeon/Slash</td><td>7</td></tr><tr><td>Strip of leather</td><td>2d4</td><td>Slash/Pierce</td><td>6</td></tr><tr><td>Glass bottle</td><td>1d2</td><td>Bludgeon</td><td>3</td></tr><tr><td>Glass pane or mirror</td><td>1</td><td>All</td><td>8</td></tr><tr><td>Rope</td><td>1d4+1</td><td>Slash</td><td>6</td></tr><tr><td>Wooden door</td><td>10d3+20</td><td>Slash</td><td>9</td></tr><tr><td>Wooden pole</td><td>2d6</td><td>Slash</td><td>7</td></tr><tr><td>Metal pole</td><td>5d6+15</td><td>Bludgeon</td><td>0</td></tr></tbody></table><h3 id="item-saving-throws" tabindex="-1"><strong>Item Saving Throws</strong> <a class="header-anchor" href="#item-saving-throws" aria-label="Permalink to &quot;**Item Saving Throws**&quot;">​</a></h3><p>Unattended items caught in area effects make saving throws instead of tracking HP. Items with a baseline save of 10 or lower rarely need to be checked unless the attack is exceptionally powerful. Protected items (inside a pack, tucked in pouches) do not need to save.</p><p>Items that fail are destroyed. Magical items add their enchantment bonus to saves. Items with no enchantment bonus (rings, potions) add +1 to +5 based on power. Items designed to resist a specific damage type gain an additional +2 against that type.</p><h3 id="table-9-12-item-saving-throws" tabindex="-1"><strong>Table 9.12: Item Saving Throws</strong> <a class="header-anchor" href="#table-9-12-item-saving-throws" aria-label="Permalink to &quot;**Table 9.12: Item Saving Throws**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Acid</th><th>Crushing</th><th>Disintegrate</th><th>Fall</th><th>Magic Fire</th><th>Fire</th><th>Cold</th><th>Lightning</th><th>Electricity</th></tr></thead><tbody><tr><td>Bone/Ivory</td><td>11</td><td>16</td><td>19</td><td>6</td><td>9</td><td>3</td><td>2</td><td>8</td><td>2</td></tr><tr><td>Cloth</td><td>12</td><td>—</td><td>19</td><td>—</td><td>16</td><td>13</td><td>2</td><td>18</td><td>2</td></tr><tr><td>Glass</td><td>5</td><td>20</td><td>19</td><td>14</td><td>7</td><td>4</td><td>6</td><td>17</td><td>2</td></tr><tr><td>Leather</td><td>10</td><td>3</td><td>19</td><td>2</td><td>6</td><td>4</td><td>3</td><td>13</td><td>2</td></tr><tr><td>Metal</td><td>13</td><td>7</td><td>17</td><td>3</td><td>6</td><td>2</td><td>2</td><td>12</td><td>2</td></tr><tr><td>Paper</td><td>16</td><td>7</td><td>19</td><td>—</td><td>19</td><td>19</td><td>2</td><td>19</td><td>2</td></tr><tr><td>Pottery</td><td>4</td><td>18</td><td>19</td><td>11</td><td>3</td><td>2</td><td>4</td><td>2</td><td>2</td></tr><tr><td>Rock/Crystal</td><td>3</td><td>17</td><td>18</td><td>8</td><td>3</td><td>2</td><td>2</td><td>14</td><td>2</td></tr><tr><td>Rope</td><td>12</td><td>2</td><td>19</td><td>—</td><td>10</td><td>6</td><td>2</td><td>9</td><td>2</td></tr><tr><td>Wood, thick</td><td>8</td><td>10</td><td>19</td><td>2</td><td>7</td><td>5</td><td>2</td><td>12</td><td>2</td></tr><tr><td>Wood, thin</td><td>9</td><td>13</td><td>19</td><td>2</td><td>11</td><td>9</td><td>2</td><td>10</td><td>2</td></tr></tbody></table><p><em>Oils and potions save as the liquid, not the container. Acid mixes with affected items even on a successful save.</em></p><hr><h2 id="touch-spells-in-combat" tabindex="-1"><strong>Touch Spells in Combat</strong> <a class="header-anchor" href="#touch-spells-in-combat" aria-label="Permalink to &quot;**Touch Spells in Combat**&quot;">​</a></h2><p>Casters can touch targets as part of casting. Most touch spells are effective only on the round cast — a missed attack loses the spell. Some allow multiple touch attempts; the spell&#39;s description specifies this.</p><p><strong>Unwilling targets.</strong> The caster makes an attack roll against AC 10, modified only by the target&#39;s Dexterity and magical bonuses. Magical armor&#39;s enchantment bonus applies; physical armor does not.</p><p><strong>Willing targets.</strong> Automatic if both characters are free from melee. Hitting a willing target performing any action other than waiting requires an attack against AC 10.</p><hr><h2 id="mounted-combat" tabindex="-1"><strong>Mounted Combat</strong> <a class="header-anchor" href="#mounted-combat" aria-label="Permalink to &quot;**Mounted Combat**&quot;">​</a></h2><p>Combat-trained mounts — warhorses and specifically bred animals — fight reliably. All other mounts are skittish. Fighting from an untrained mount imposes −2 to the rider&#39;s attack rolls. If an untrained mount takes damage or is startled (sudden loud noise, unexpected contact), the rider makes a Wisdom check at +3 to calm it, or the mount panics for 1d4 rounds — bolting in a random direction at 1.5× its movement value.</p><p><strong>Melee advantages.</strong> Mounted riders gain +1 to attack rolls against targets smaller than the mount. Attackers smaller than the mount suffer −1 to hit the rider.</p><p><strong>Ranged weapons.</strong> Short bows, composite short bows, and light crossbows can be fired from horseback. Heavy crossbows can be fired but not reloaded while mounted. A stationary mount allows full rate of fire. A moving mount reduces ROF by 1.</p><h3 id="table-9-13-mounted-missile-penalties" tabindex="-1"><strong>Table 9.13: Mounted Missile Penalties</strong> <a class="header-anchor" href="#table-9-13-mounted-missile-penalties" aria-label="Permalink to &quot;**Table 9.13: Mounted Missile Penalties**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mount Speed</th><th>Attack Modifier</th></tr></thead><tbody><tr><td>Stationary</td><td>0</td></tr><tr><td>Less than ½ normal rate</td><td>−2</td></tr><tr><td>½ to ¾ normal rate</td><td>−4</td></tr><tr><td>Greater than ¾ normal rate</td><td>−6</td></tr></tbody></table><p><strong>Mount killed.</strong> A rider whose mount dies falls prone and takes 1d3 damage unless a Wisdom check at +3 allows them to land safely.</p><hr><h2 id="siege-combat" tabindex="-1"><strong>Siege Combat</strong> <a class="header-anchor" href="#siege-combat" aria-label="Permalink to &quot;**Siege Combat**&quot;">​</a></h2><p>Siege weapons attack structures rather than creatures. Match the siege weapon to the structural material and roll a saving throw. If the roll falls below the target number, the structure gives way. For each point below the target, one cubic foot of material is destroyed.</p><h3 id="table-9-14-structural-saving-throws" tabindex="-1"><strong>Table 9.14: Structural Saving Throws</strong> <a class="header-anchor" href="#table-9-14-structural-saving-throws" aria-label="Permalink to &quot;**Table 9.14: Structural Saving Throws**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Siege Weapon</th><th>Hard Stone</th><th>Soft Stone</th><th>Earth</th><th>Thin Wood</th><th>Thick Wood</th></tr></thead><tbody><tr><td>Ballista</td><td>2</td><td>3</td><td>4</td><td>10</td><td>5</td></tr><tr><td>Giant&#39;s fist</td><td>3</td><td>4</td><td>7</td><td>16</td><td>9</td></tr><tr><td>Small catapult</td><td>4</td><td>8</td><td>5</td><td>17</td><td>9</td></tr><tr><td>Ram</td><td>5</td><td>9</td><td>3</td><td>20</td><td>17</td></tr><tr><td>Screw/drill</td><td>12</td><td>15</td><td>16</td><td>20</td><td>12</td></tr><tr><td>Large catapult</td><td>8</td><td>11</td><td>10</td><td>20</td><td>13</td></tr></tbody></table><hr><h1 id="playing-without-a-grid" tabindex="-1"><strong>Playing Without a Grid</strong> <a class="header-anchor" href="#playing-without-a-grid" aria-label="Permalink to &quot;**Playing Without a Grid**&quot;">​</a></h1><p>The game&#39;s distances assume a battle grid with 1.5-meter squares. Groups playing without one can replace precise measurements with three informal range bands:</p><ul><li><strong>Close</strong> — within arm&#39;s reach, or near enough that melee is unavoidable. Melee weapons and touch spells work here.</li><li><strong>Nearby</strong> — across the room, or roughly 20 meters in open terrain. Missile weapons, most combat spells, and short-range abilities work here.</li><li><strong>Distant</strong> — the far end of the battlefield, or beyond. Only long-range missiles, extended spells, and movement across multiple rounds reach here.</li></ul><p>When a rule specifies an exact distance, translate it mentally: up to 3 meters is Close, up to 20 meters is Nearby, and beyond that is Distant. For area effects — fireballs, cone attacks, burst spells — the GM judges whether bystanders in the same zone are affected based on how the scene was described.</p><p>This approach trades precision for pace. It works well in open terrain and loose narrative scenes. For trap-heavy dungeons and complex tactical encounters, the grid earns its keep.</p>',250)])])}const u=e(n,[["render",o]]);export{p as __pageData,u as default};
